  ('elementary-6e11b43e-moex-00090', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '有關「西拉雅族原住民身分案」，我國憲法法庭111年10月28日判決原住民身分法相關條文與憲法意 旨有違，應於幾年內修法或另定特別法？', '["1年", "2年", "3年", "4年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00091', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '中華民國總統於那一年的「原住民族日」當天，代表政府向原住民族公開正式道歉，後續亦設立「總統府 原住民族歷史正義與轉型正義委員會」並展開問題釐清與責任歸屬的相關行政作為？', '["2015年1月1日", "2015年8月1日", "2016年1月1日", "2016年8月1日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00092', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '我國現行文化資產保存法將文化資產區分為有形文化資產與無形文化資產。其中，有形文化資產當中的 「聚落建築群」類別定義為「指建築式樣、風格特殊或與景觀協調，而具有歷史、藝術或科學價值之建造 物群或街區」。下列何者不是我國已經公告登錄之原住民族「聚落建築群」？', '["Kapayuwanan（舊筏灣）聚落建築群", "Padain傳統聚落（高燕及射鹿）", "Tjuvecekadan（老七佳部落）石板屋聚落", "蘭嶼雅美族野銀部落傳統建築"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00093', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '依照原住民族教育法規定，取得教師證書，並經公開甄選獲聘任為高級中等以下原住民重點學校或偏遠地 區學校編制內合格專任教師者，應於原住民重點學校或偏遠地區學校任教民族教育課程至少幾年，始得提 出申請介聘至非原住民重點學校或非偏遠地區學校服務？', '["3年", "5年", "6年", "7年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00094', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '現行原住民族委員會組織法明定該會置委員19人至29人。請問，其委員組成不包含下列何者？', '["原住民族各族代表", "有關機關代表", "原住民籍立法委員", "學者、專家"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
