  ('elementary-6e11b43e-moex-00096', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '現行原住民保留地開發管理辦法第6條明定原住民保留地所在之鄉（鎮、市、區）公所設置原住民保留地 土地權利審查委員會，其掌理事項不包含下列何者？', '["原住民保留地土地權利糾紛之調查及調處事項", "申請租用、無償使用原住民保留地之審查事項", "原住民保留地分配土地補償之協議事項", "原住民保留地買賣鑑價之審查事項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00097', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '「政府應建立合宜機制，尊重、維護、保存傳統用海智慧等海洋文化資產，保障與傳承原住民族傳統用海 文化及權益，並兼顧漁業科學管理」此一條文，係明定於下列何項法規之中？', '["文化資產保存法", "原住民族文化資產處理辦法", "原住民族基本法", "海洋基本法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
